func FetchAllUsers(urls []string) []string {
	var results []string
	for _, url := range urls {
		go func() {
			resp, _ := http.Get(url)
			body, _ := io.ReadAll(resp.Body)
			results = append(results, string(body))
		}()
	}
	return results
